    fn dispmsg(&mut self) {
        self.set_a(self.mem[sym::msgtimer]);
        if self.reg.a == 0x00 {
            return;
        }
        let _v = self.mem[sym::msgtimer].wrapping_sub(1);
        self.mem[sym::msgtimer] = _v;
        self.set_nz(_v);
        self.set_a(self.mem[sym::KidLife]);
        if (self.reg.a as i8) < 0 {
            self.set_a(self.mem[sym::msgtimer]);
            if self.reg.a >= 0x12 {
                return;
            }
            self.set_a(self.mem[sym::message]);
            if self.reg.a != 0x01 {
                if self.reg.a != 0x03 {
                    return;
                }
                self.timeleftmsg();
                return;
            }
            self.printlevel();
            return;
        }
        self.set_a(self.mem[sym::msgtimer]);
        if self.reg.a < 0x0f {
            return;
        }
        if self.reg.a >= 0x5f {
            self.continuemsg();
            return;
        }
        self.set_a(self.reg.a & 0x07);
        if self.reg.a >= 0x03 {
            return;
        }
        if self.reg.a != 0x02 {
            self.continuemsg();
            return;
        }
        self.set_a(self.mem[sym::soundon]);
        if self.reg.a == 0x00 {
            self.gtone();
        }
        self.set_a(0x10);
        self.addsound();
        self.continuemsg();
        return;
    }

